import { useEffect, useState } from "react";

import HodLayout
from "../../layouts/HodLayout";

import facultyQuestions
from "../../data/facultyQuestions";

import {
  getFacultySubmissions,
  approveSubmission,
  rejectSubmission
} from "../../api/hodApi";

function FacultyReview() {

  const [submissions, setSubmissions] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [remarks, setRemarks] =
    useState({});

  const [selectedSubmission, setSelectedSubmission] =
    useState(null);

  const [activeTab, setActiveTab] =
  useState("pending");

const pendingReviews =
  submissions.filter(
    (s) =>
      s.status ===
      "Pending HOD Approval"
  );

const approvedReviews =
  submissions.filter(
    (s) =>
      s.status ===
      "Approved by HOD"
  );

const rejectedReviews =
  submissions.filter(
    (s) =>
      s.status ===
      "Rejected by HOD"
  );

let displayData = [];

if (activeTab === "pending") {
  displayData = pendingReviews;
}

if (activeTab === "approved") {
  displayData = approvedReviews;
}

if (activeTab === "rejected") {
  displayData = rejectedReviews;
}

  useEffect(() => {

    fetchSubmissions();

  }, []);

  const fetchSubmissions =
    async () => {

      try {

        const response =
          await getFacultySubmissions();

        setSubmissions(
          response.data.submissions || []
        );

      } catch (error) {

        console.error(error);

      } finally {

        setLoading(false);

      }

    };

  const handleApprove =
    async (id) => {

      try {

        await approveSubmission(id);

        alert(
          "Submission Approved Successfully"
        );

        fetchSubmissions();

      } catch (error) {

        console.error(error);

        alert(
          "Approval Failed"
        );

      }

    };

  const handleReject =
    async (id) => {

      try {

        const reason =
          remarks[id] || "";

        if (!reason.trim()) {

          alert(
            "Please enter rejection reason"
          );

          return;

        }

        await rejectSubmission(
          id,
          reason
        );

        alert(
          "Submission Rejected Successfully"
        );

        fetchSubmissions();

      } catch (error) {

        console.error(error);

        alert(
          "Reject Failed"
        );

      }

    };

  return (

<HodLayout>

<div
  style={{
    padding: "30px",
    minHeight: "100vh",
    background:
      "linear-gradient(180deg,#eef4ff 0%,#f8fafc 100%)"
  }}
>

     <div
  style={{
    background:
      "linear-gradient(135deg,#2563eb,#1e40af)",
    color: "white",
    padding: "30px",
    borderRadius: "15px",
    marginBottom: "25px",
    boxShadow:
      "0 8px 20px rgba(37,99,235,0.2)"
  }}
>
  <h1
    style={{
      margin: 0
    }}
  >
    Faculty Reviews
  </h1>

  <p
    style={{
      marginTop: "10px",
      marginBottom: 0
    }}
  >
    Review Faculty Quarterly Reports
  </p>
</div>
      
      <div
  style={{
    display: "flex",
    gap: "10px",
    marginTop: "20px",
    marginBottom: "20px"
  }}
>
  <button
    onClick={() =>
      setActiveTab("pending")
    }
    style={{
      padding: "10px 15px",
      background:
        activeTab === "pending"
          ? "#2563eb"
          : "#e5e7eb",
      color:
        activeTab === "pending"
          ? "white"
          : "black",
      border: "none",
      borderRadius: "6px",
      cursor: "pointer"
    }}
  >
    Pending Reviews
  </button>

  <button
    onClick={() =>
      setActiveTab("approved")
    }
    style={{
      padding: "10px 15px",
      background:
        activeTab === "approved"
          ? "#16a34a"
          : "#e5e7eb",
      color:
        activeTab === "approved"
          ? "white"
          : "black",
      border: "none",
      borderRadius: "6px",
      cursor: "pointer"
    }}
  >
    Approved Reviews
  </button>

  <button
    onClick={() =>
      setActiveTab("rejected")
    }
    style={{
      padding: "10px 15px",
      background:
        activeTab === "rejected"
          ? "#dc2626"
          : "#e5e7eb",
      color:
        activeTab === "rejected"
          ? "white"
          : "black",
      border: "none",
      borderRadius: "6px",
      cursor: "pointer"
    }}
  >
    Rejected Reviews
  </button>
</div>

      {

        loading ?

        <p>
          Loading...
        </p>

        :

        <table
          style={{
            width: "100%",
            marginTop: "20px",
            borderCollapse:
              "collapse"
          }}
        >

          <thead>

            <tr>

              <th style={thStyle}>
                Faculty
              </th>

              <th style={thStyle}>
                Email
              </th>

              <th style={thStyle}>
                Quarter
              </th>

              <th style={thStyle}>
                Answered
              </th>

              <th style={thStyle}>
                Status
              </th>

              <th style={thStyle}>
                Remarks
              </th>

              <th style={thStyle}>
                Actions
              </th>

            </tr>

          </thead>

          <tbody>

            {

              displayData.map(
                (
                  item
                ) => (

                  <tr
                    key={
                      item._id
                    }
                  >

                    <td style={tdStyle}>
                      {
                        item.facultyName
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.facultyEmail
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.quarter
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.answeredCount
                      }
                      /
                      {
                        item.totalQuestions
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.status
                      }
                    </td>

                    <td style={tdStyle}>

                      <textarea
                        rows="2"
                        placeholder="Reason if rejecting..."
                        value={
                          remarks[item._id] || ""
                        }
                        onChange={(e) =>
                          setRemarks({
                            ...remarks,
                            [item._id]:
                              e.target.value
                          })
                        }
                        style={{
                          width: "100%"
                        }}
                      />

                    </td>

                    <td style={tdStyle}>

                      <button
                        onClick={() =>
                          setSelectedSubmission(
                            item
                          )
                        }
                        style={viewBtn}
                      >
                        View
                      </button>

                     {
activeTab !== "approved" && (
  <button
    onClick={() =>
      handleApprove(
        item._id
      )
    }
    style={approveBtn}
  >
    Approve
  </button>
)
}

{
activeTab !== "rejected" && (
  <button
    onClick={() =>
      handleReject(
        item._id
      )
    }
    style={rejectBtn}
  >
    Reject
  </button>
)
}

                    </td>

                  </tr>

                )
              )

            }

          </tbody>

        </table>

      }

      {

        selectedSubmission && (

          <div
            style={{
              position: "fixed",
              top: 0,
              left: 0,
              width: "100%",
              height: "100%",
              background:
                "rgba(0,0,0,0.5)",
              display: "flex",
              justifyContent:
                "center",
              alignItems:
                "center"
            }}
          >

            <div
  style={{
    background: "white",
    padding: "25px",
    width: "80%",
    maxHeight:
      "80vh",
    overflowY:
      "auto",
    borderRadius:
      "12px",
    position:
      "relative"
  }}
 >

<div
  style={{
    position: "sticky",
    top: 0,
    background: "white",
    zIndex: 1000,
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    paddingBottom: "10px",
    borderBottom:
      "1px solid #e5e7eb",
    marginBottom: "20px"
  }}
>
  <h2
    style={{
      margin: 0
    }}
  >
    Faculty Answers
  </h2>

  <button
    onClick={() =>
      setSelectedSubmission(null)
    }
    style={{
      background:"#dc2626",
      color:"#fff",
      border:"none",
      padding:"8px 15px",
      borderRadius:"6px",
      cursor:"pointer"
    }}
  >
    ✕ Close
  </button>
</div>

<div
  style={{
    marginBottom: "20px",
    background: "#f3f4f6",
    padding: "15px",
    borderRadius: "8px"
  }}
>
  <p>
    <strong>Faculty :</strong>
    {" "}
    {selectedSubmission.facultyName}
  </p>

  <p>
    <strong>Email :</strong>
    {" "}
    {selectedSubmission.facultyEmail}
  </p>

  <p>
    <strong>Quarter :</strong>
    {" "}
    {selectedSubmission.quarter}
  </p>

  <p>
    <strong>Total Questions :</strong>
    {" "}
    {selectedSubmission.totalQuestions}
  </p>

  <p>
    <strong>Answered :</strong>
    {" "}
    {selectedSubmission.answeredCount}
  </p>

  <p>
    <strong>Unanswered :</strong>
    {" "}
    {selectedSubmission.unansweredCount}
  </p>

</div>

<table
  style={{
    width: "100%",
    borderCollapse: "collapse"
  }}
>
  <thead>

    <tr>

       <th style={thStyle}>
         Question Key
       </th>

      <th style={thStyle}>
        Answer
      </th>

    </tr>

  </thead>

   <tbody>

{
facultyQuestions.map(
(section)=>{

return (

<>

<tr>

<td
colSpan="2"
style={{
background:"#dbeafe",
fontWeight:"bold",
padding:"12px"
}}
>

Section {section.sectionNo}
 -
 {section.sectionTitle}

</td>

</tr>

{

section.questions.map(
(question,index)=>{

const key =
`${section.sectionNo}_${index}`;

const answerObj =
selectedSubmission.answers?.find(
(a)=>
a.questionNo === key
);

return (

<tr key={key}>

<td style={tdStyle}>
{question.question}
</td>

<td style={tdStyle}>

{
answerObj?.answer ?

(
String(answerObj.answer)
.includes("/uploads/faculty/")

?

<img
  src={`http://localhost:5000${answerObj.answer}`}
  alt="Faculty Upload"
  style={{
    maxWidth:"250px",
    borderRadius:"8px"
  }}
/>

:

String(answerObj.answer)
)

:

"Not Answered"

}

</td>

</tr>

);

}
)

}

</>

);

}
)

}

</tbody>

</table>
      

            </div>

          </div>

        )

      }

   </div>

</HodLayout>

);

}

