  background:
    "#2563eb",

  color:
    "white",

  border:
    "none",

  padding:
    "8px 12px",

  marginRight:
    "5px",

  cursor:
    "pointer",

  borderRadius:
    "5px"

};

const approveBtn = {

  background:
    "#16a34a",

  color:
    "white",

  border:
    "none",

  padding:
    "8px 12px",

  marginRight:
    "5px",

  cursor:
    "pointer",

  borderRadius:
    "5px"

};

const rejectBtn = {

  background:
    "#dc2626",

  color:
    "white",

  border:
    "none",

  padding:
    "8px 12px",

  cursor:
    "pointer",

  borderRadius:
    "5px"

};

